function ProductCard({ product, onView, onAdd }) {
  const [selOpt, setSelOpt] = useState(product.options[0]);
  const [modal, setModal]   = useState(false);
  const price = product.prices?.[selOpt] ?? product.price;
  const bs = BADGE_STYLE[product.badge] || BADGE_STYLE.New;

  return (
    <>
      <div style={{ ...S.card }}
        onMouseEnter={e => { e.currentTarget.style.transform="translateY(-4px)"; e.currentTarget.style.boxShadow="0 14px 40px rgba(0,0,0,0.13)"; }}
        onMouseLeave={e => { e.currentTarget.style.transform="translateY(0)"; e.currentTarget.style.boxShadow="0 4px 20px rgba(0,0,0,0.07)"; }}>
        {/* Image */}
        <div onClick={() => onView(product)}
          style={{ height:220,overflow:"hidden",background:"#f5f5f5",cursor:"pointer",position:"relative" }}>
          <img src={product.img} alt={product.name}
            style={{ width:"100%",height:"100%",objectFit:"cover",transition:"transform 0.4s" }}
            onMouseEnter={e => e.target.style.transform="scale(1.06)"}
            onMouseLeave={e => e.target.style.transform="scale(1)"} />
          <span style={{ position:"absolute",top:12,left:12,background:bs.bg,color:bs.color,
            padding:"4px 12px",borderRadius:20,fontSize:11,fontWeight:700 }}>
            {product.badge}
          </span>
        </div>
        {/* Body */}
        <div style={{ padding:20 }}>
          <div style={{ fontSize:11,color:"#aaa",fontWeight:600,letterSpacing:1,
            textTransform:"uppercase",marginBottom:4 }}>{product.cat}</div>
          <div onClick={() => onView(product)}
            style={{ fontWeight:700,fontSize:16,color:"#1a1a1a",marginBottom:6,cursor:"pointer" }}>
            {product.name}
          </div>
          {/* Options */}
          <div style={{ display:"flex",gap:6,flexWrap:"wrap",marginBottom:14 }}>
            {product.options.map(o => (
              <button key={o} onClick={() => setSelOpt(o)}
                style={{ padding:"4px 10px",borderRadius:20,fontSize:11,fontWeight:600,cursor:"pointer",
                  background: selOpt===o ? S.navy : "#f5f5f5",
                  color: selOpt===o ? "#fff" : "#666",
                  border: selOpt===o ? `1px solid ${S.navy}` : "1px solid #e0e0e0" }}>
                {o}
              </button>
            ))}
          </div>
          <div style={{ display:"flex",alignItems:"center",justifyContent:"space-between" }}>
            <div>
              <div style={{ fontWeight:800,fontSize:20,color:S.navy }}>₹{price.toLocaleString()}</div>
              <div style={{ fontSize:11,color:S.orange,fontWeight:600 }}>{product.unit}</div>
            </div>
            <button onClick={() => setModal(true)}
              style={{ background:S.navy,color:"#fff",border:"none",padding:"10px 18px",
                borderRadius:40,fontSize:13,fontWeight:700,cursor:"pointer" }}>
              Add to Cart
            </button>
          </div>
        </div>
      </div>
      {modal && (
        <AddToCartModal product={product} selOpt={selOpt}
          onClose={() => setModal(false)}
          onConfirm={extra => { onAdd(product, selOpt, extra); setModal(false); }} />
      )}
    </>
  );
}

