function ProductDetailPage({ product, onBack, onAdd }) {
  const [selOpt, setSelOpt]   = useState(product.options[0]);
  const [qty, setQty]         = useState(product.minQty || 1);
  const [selLeaf, setSelLeaf] = useState(product.leafOptions?.[0] || null);
  const [tab, setTab]         = useState("details");
  const [file, setFile]       = useState(null);
  const [details, setDetails] = useState({ fullName:"",jobTitle:"",company:"",phone:"",email:"",website:"",address:"" });
  const [added, setAdded]     = useState(false);
  const isCard = product.cat === "Cards";
  const basePrice = product.prices?.[selOpt] ?? product.price;
  const hasBulk   = product.bulkDiscount && qty > product.bulkDiscount.qty;
  const discount  = hasBulk ? product.bulkDiscount.pct : 0;
  const price     = Math.round(basePrice * (1 - discount/100));
  const total     = price * qty;

  const handleAdd = async () => {
    const isCanvas = product.cat === "Art";
    let uploadedUrl = null;

    if (isCanvas && file) {
      setAdded("uploading");
      try {
        const formData = new FormData();
        formData.append("image", file);
        formData.append("productName", product.name);
        formData.append("size", selOpt);
        const res = await fetch(`${API}/canvas-upload`, { method:"POST", body:formData });
        const data = await res.json();
        if (data.success) uploadedUrl = data.url;
      } catch(e) {
        console.error("Upload failed", e);
      }
    }

    const extra = tab==="upload"
      ? {mode:"upload", fileName:file?.name, leafs:selLeaf, uploadedUrl}
      : {mode:"details", details, leafs:selLeaf};
    onAdd(product, selOpt, extra);
    setAdded(true);
    setTimeout(() => setAdded(false), 2000);
  };

  return (
    <div style={{ maxWidth:1100,margin:"0 auto",padding:"48px 32px" }}>
      <button onClick={onBack} style={{ background:"none",border:"none",color:"#888",
        fontSize:14,cursor:"pointer",marginBottom:32,display:"flex",alignItems:"center",gap:6 }}>
        ← Back to Products
      </button>
      <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:56,alignItems:"start" }}>
        {/* Image */}
        <div style={{ borderRadius:20,overflow:"hidden",boxShadow:"0 8px 40px rgba(0,0,0,0.12)" }}>
          <img src={product.img} alt={product.name} style={{ width:"100%",aspectRatio:"4/3",objectFit:"cover" }} />
        </div>
        {/* Details */}
        <div>
          <div style={{ fontSize:12,color:"#aaa",fontWeight:600,letterSpacing:1,
            textTransform:"uppercase",marginBottom:8 }}>{product.cat}</div>
          <h1 style={{ fontFamily:"'DM Serif Display',serif",fontSize:36,color:S.navy,marginBottom:12 }}>
            {product.name}
          </h1>
          <p style={{ color:"#666",lineHeight:1.7,marginBottom:20 }}>{product.desc}</p>
          <div style={{ marginBottom:24 }}>
            <div style={{ display:"flex",alignItems:"baseline",gap:12,flexWrap:"wrap" }}>
              <span style={{ fontWeight:800,fontSize:38,color:S.navy }}>₹{price.toLocaleString()}</span>
              {hasBulk && (
                <span style={{ fontWeight:700,fontSize:16,color:"#aaa",textDecoration:"line-through" }}>
                  ₹{basePrice.toLocaleString()}
                </span>
              )}
              <span style={{ fontSize:14,color:S.orange,fontWeight:600 }}>{product.unit}</span>
            </div>
            {hasBulk && (
              <div style={{ display:"inline-flex",alignItems:"center",gap:6,background:"#dcfce7",
                color:"#166534",padding:"5px 14px",borderRadius:20,fontSize:13,fontWeight:700,marginTop:6 }}>
                🎉 {discount}% Bulk Discount Applied! (Over {product.bulkDiscount.qty} pcs)
              </div>
            )}
            {!hasBulk && product.bulkDiscount && qty <= product.bulkDiscount.qty && (
              <div style={{ fontSize:12,color:"#888",marginTop:6 }}>
                💡 Order more than {product.bulkDiscount.qty} pcs to get <strong style={{color:S.orange}}>{product.bulkDiscount.pct}% off!</strong>
              </div>
            )}
            <div style={{ fontWeight:700,fontSize:14,color:"#555",marginTop:8 }}>
              Total: <span style={{ color:S.navy }}>₹{total.toLocaleString()}</span> for {qty} pcs
            </div>
          </div>
          {/* Options */}
          <div style={{ marginBottom:20 }}>
            <div style={{ fontSize:12,fontWeight:700,color:"#555",textTransform:"uppercase",
              letterSpacing:0.5,marginBottom:10 }}>Finish / Material</div>
            <div style={{ display:"flex",gap:8,flexWrap:"wrap" }}>
              {product.options.map(o => (
                <button key={o} onClick={() => setSelOpt(o)}
                  style={{ padding:"8px 18px",borderRadius:40,fontSize:13,fontWeight:600,cursor:"pointer",
                    background: selOpt===o ? S.navy : "#fff",
                    color: selOpt===o ? "#fff" : "#666",
                    border: selOpt===o ? `1px solid ${S.navy}` : "1px solid #ddd" }}>
                  {o}{product.prices ? ` — ₹${product.prices[o]?.toLocaleString()}` : ""}
                </button>
              ))}
            </div>
          </div>
          {/* Leaf Options */}
          {product.leafOptions && (
            <div style={{ marginBottom:20 }}>
              <div style={{ fontSize:12,fontWeight:700,color:"#555",textTransform:"uppercase",
                letterSpacing:0.5,marginBottom:10 }}>Number of Leafs</div>
              <div style={{ display:"flex",gap:8 }}>
                {product.leafOptions.map(l => (
                  <button key={l} onClick={() => setSelLeaf(l)}
                    style={{ padding:"8px 20px",borderRadius:40,fontSize:13,fontWeight:600,cursor:"pointer",
                      background: selLeaf===l ? S.orange : "#fff",
                      color: selLeaf===l ? "#fff" : "#666",
                      border: selLeaf===l ? `1px solid ${S.orange}` : "1px solid #ddd" }}>
                    {l}
                  </button>
                ))}
              </div>
              <div style={{ fontSize:12,color:"#888",marginTop:8 }}>
                {selLeaf==="7 Leafs"
                ? "📅 7 Leafs: Includes 1 cover page and 12 months with front & back printing — each leaf is printed on both sides to cover all 12 months."
                : "📅 13 Leafs: Includes 1 cover page and 12 different leafs — each leaf is dedicated to one individual month for a complete full-year calendar."}
              </div>
            </div>
          )}

          {/* Qty */}
          <div style={{ marginBottom:24 }}>
            <div style={{ fontSize:12,fontWeight:700,color:"#555",textTransform:"uppercase",
              letterSpacing:0.5,marginBottom:10 }}>
              Quantity {product.minQty ? <span style={{ color:S.orange }}>(Min. {product.minQty} pcs)</span> : ""}
            </div>
            <div style={{ display:"flex",alignItems:"center",gap:12 }}>
              <button onClick={() => setQty(Math.max(product.minQty||1, qty-1))}
                style={{ width:36,height:36,borderRadius:50,border:"1px solid #ddd",
                  background:"#fff",fontSize:18,cursor:"pointer" }}>−</button>
              <span style={{ fontWeight:700,fontSize:18,minWidth:30,textAlign:"center" }}>{qty}</span>
              <button onClick={() => setQty(qty+1)}
                style={{ width:36,height:36,borderRadius:50,border:"1px solid #ddd",
                  background:"#fff",fontSize:18,cursor:"pointer" }}>+</button>
            </div>
          </div>
          {/* Canvas upload notice */}
          {product.cat === "Art" && (
            <div style={{ background:"#fffbeb",border:"1px solid #fde68a",borderRadius:12,
              padding:"12px 16px",marginBottom:20,fontSize:13,color:"#92400e" }}>
              📸 <strong>Upload your photo</strong> — we'll print it on premium canvas and email you a preview before printing.
            </div>
          )}

          {/* Card detail / upload tabs */}
          {isCard && (
            <div style={{ marginBottom:20 }}>
              <div style={{ display:"flex",borderBottom:"2px solid #f0f0f0",marginBottom:16 }}>
                {[{k:"details",l:"📝 Fill Card Details"},{k:"upload",l:"⬆ Upload Design"}].map(t => (
                  <button key={t.k} onClick={() => setTab(t.k)}
                    style={{ padding:"9px 16px",border:"none",background:"none",fontWeight:700,
                      fontSize:13,cursor:"pointer",color: tab===t.k ? S.navy : "#aaa",
                      borderBottom: tab===t.k ? `2px solid ${S.navy}` : "2px solid transparent",
                      marginBottom:-2 }}>
                    {t.l}
                  </button>
                ))}
              </div>
              {tab==="details" ? (
                <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:10 }}>
                  {[
                    {k:"fullName",l:"Full Name",p:"Rahul Sharma",s:2},
                    {k:"jobTitle",l:"Job Title",p:"Marketing Manager",s:1},
                    {k:"company",l:"Company",p:"Acme Pvt. Ltd.",s:1},
                    {k:"phone",l:"Phone",p:"+91 98765 43210",s:1},
                    {k:"email",l:"Email",p:"rahul@company.com",s:1},
                  ].map(f => (
                    <div key={f.k} style={{ gridColumn:f.s===2?"1/-1":"auto" }}>
                      <label style={{ fontSize:11,fontWeight:700,color:"#666",display:"block",marginBottom:4 }}>{f.l}</label>
                      <input value={details[f.k]}
                        onChange={e => setDetails(p => ({...p,[f.k]:e.target.value}))}
                        placeholder={f.p}
                        style={{ width:"100%",padding:"9px 12px",borderRadius:8,
                          border:"1px solid #e0e0e0",fontSize:13,boxSizing:"border-box" }} />
                    </div>
                  ))}
                </div>
              ) : (
                <UploadArea file={file} setFile={setFile} />
              )}
            </div>
          )}
          {!isCard && product.cat === "Art" && (
            <div style={{ marginBottom:20 }}>
              <div style={{ fontSize:12,fontWeight:700,color:"#555",textTransform:"uppercase",
                letterSpacing:0.5,marginBottom:10 }}>Upload Your Photo / Artwork</div>
              <UploadArea file={file} setFile={setFile} />
            </div>
          )}
          <button onClick={handleAdd}
            style={{ width:"100%",padding:"15px",background: added ? "#22c55e" : S.navy,
              color:"#fff",border:"none",borderRadius:50,fontSize:16,fontWeight:700,cursor:"pointer",
              transition:"background 0.3s" }}>
            {added === "uploading" ? "⏳ Uploading your image…"
              : added ? "✓ Added to Cart!"
              : `Add to Cart — ₹${total.toLocaleString()}`}
          </button>
        </div>
      </div>
    </div>
  );
}

