function ContactPage() {
  const [form, setForm] = useState({name:"",email:"",message:""});
  const [sent, setSent] = useState(false);
  const [loading, setLoading] = useState(false);

  const [error, setError] = useState("");

  const handle = async () => {
    if (!form.name || !form.email || !form.message) {
      setError("Please fill in all fields.");
      return;
    }
    setError("");
    setLoading(true);
    try {
      const res = await fetch(`${API}/contact`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      if (res.ok) {
        setSent(true);
      } else {
        setError(data.message || "Something went wrong. Please try again.");
      }
    } catch (e) {
      setError("Could not connect. Please try again later.");
    }
    setLoading(false);
  };

  return (
    <div style={{ maxWidth:680,margin:"0 auto",padding:"72px 32px",textAlign:"center" }}>
      <h1 style={{ fontFamily:"'DM Serif Display',serif",fontSize:48,color:S.navy,marginBottom:12 }}>Get in Touch</h1>
      <p style={{ color:"#888",marginBottom:48,fontSize:15 }}>Have a question or custom order? We'd love to hear from you.</p>
      {sent ? (
        <div style={{ background:"#f0fff4",border:"1px solid #9ae6b4",borderRadius:16,padding:40,color:"#276749" }}>
          <div style={{ fontSize:48,marginBottom:16 }}>✅</div>
          <div style={{ fontWeight:700,fontSize:18 }}>Message Sent!</div>
          <div style={{ fontSize:14,marginTop:8 }}>We'll get back to you within 24 hours.</div>
        </div>
      ) : (
        <div style={{ background:"#f8f9fb",borderRadius:20,padding:36,textAlign:"left",border:"1px solid #eee" }}>
          {[{k:"name",l:"Name",t:"text",p:"Your Name"},{k:"email",l:"Email",t:"email",p:"you@example.com"}].map(f => (
            <div key={f.k} style={{ marginBottom:18 }}>
              <label style={{ fontSize:12,fontWeight:700,color:"#555",letterSpacing:0.5,
                textTransform:"uppercase",display:"block",marginBottom:6 }}>{f.l}</label>
              <input type={f.t} value={form[f.k]}
                onChange={e => setForm(p => ({...p,[f.k]:e.target.value}))}
                placeholder={f.p}
                style={{ width:"100%",padding:"12px 14px",borderRadius:10,border:"1px solid #e0e0e0",
                  fontSize:14,boxSizing:"border-box" }} />
            </div>
          ))}
          <div style={{ marginBottom:22 }}>
            <label style={{ fontSize:12,fontWeight:700,color:"#555",letterSpacing:0.5,
              textTransform:"uppercase",display:"block",marginBottom:6 }}>Message</label>
            <textarea rows={5} value={form.message}
              onChange={e => setForm(p => ({...p,message:e.target.value}))}
              placeholder="Tell us about your print requirements…"
              style={{ width:"100%",padding:"12px 14px",borderRadius:10,border:"1px solid #e0e0e0",
                fontSize:14,resize:"vertical",boxSizing:"border-box" }} />
          </div>
          {error && (
            <div style={{ background:"#fef2f2",border:"1px solid #fecaca",borderRadius:10,
              padding:"10px 14px",color:"#b91c1c",fontSize:13,marginBottom:14 }}>
              ⚠️ {error}
            </div>
          )}
          <button onClick={handle} disabled={loading}
            style={{ width:"100%",padding:"14px",background: loading ? "#888" : S.navy,
              color:"#fff",border:"none",borderRadius:50,fontSize:15,fontWeight:700,cursor:"pointer" }}>
            {loading ? "Sending…" : "Send Message →"}
          </button>
          <div style={{ marginTop:28,paddingTop:24,borderTop:"1px solid #eee",
            display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,textAlign:"center" }}>
            {[{icon:"📧",l:"Email",v:"design.printworld@gmail.com"},{icon:"📍",l:"Location",v:"India — Nationwide Delivery"}].map(c => (
              <div key={c.l}>
                <div style={{ fontSize:24,marginBottom:6 }}>{c.icon}</div>
                <div style={{ fontSize:11,color:"#aaa",fontWeight:700,textTransform:"uppercase",letterSpacing:1 }}>{c.l}</div>
                <div style={{ fontSize:13,color:"#555",marginTop:4 }}>{c.v}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

