// ─── MAIN APP ────────────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage]         = useState("home");
  const [cart, setCart]         = useState([]);
  const [cartOpen, setCartOpen] = useState(false);
  const [detail, setDetail]     = useState(null);

  const addToCart = (product, option, extra) => {
    const price = product.prices?.[option] ?? product.price;
    const key   = `${product.id}-${option}-${Date.now()}`;
    setCart(prev => [...prev, { key, product, option, name:product.name, price, extra }]);
  };

  const removeFromCart = key => setCart(prev => prev.filter(i => i.key !== key));

  const viewProduct = (product) => { setDetail(product); setPage("detail"); };

  // inject fonts
  if (typeof document !== "undefined" && !document.getElementById("pwfonts")) {
    const l = document.createElement("link");
    l.id = "pwfonts";
    l.rel = "stylesheet";
    l.href = "https://fonts.googleapis.com/css2?family=DM+Serif+Display&family=DM+Sans:wght@400;500;600;700;800&display=swap";
    document.head.appendChild(l);
  }

  return (
    <div style={{ fontFamily:"'DM Sans',sans-serif",minHeight:"100vh",background:"#fff" }}>

      <Navbar page={page} setPage={p => { setPage(p); setDetail(null); }}
        cartCount={cart.length} setCartOpen={setCartOpen} />
      {page === "home"     && <HomePage setPage={setPage} onView={viewProduct} onAdd={addToCart} />}
      {page === "products" && <ProductsPage onView={viewProduct} onAdd={addToCart} />}
      {page === "detail"   && detail && <ProductDetailPage product={detail}
        onBack={() => setPage("products")} onAdd={addToCart} />}
      {page === "about"    && <AboutPage />}
      {page === "contact"  && <ContactPage />}
      <Footer setPage={setPage} />
      {cartOpen && <CartDrawer cart={cart} onClose={() => setCartOpen(false)}
        onRemove={removeFromCart} onQtyChange={() => {}} />}
    </div>
  );
}
